use strict;
use warnings;
use Storable qw(nstore retrieve);
use CGI qw(:standard);

my $temp_dir = "/tmp";

sub load_session {
    my ($sid) = @_;
    return retrieve("/$temp_dir/sess_$sid") if -e "/$temp_dir/sess_$sid";
}

sub save_session {
    my ($sid, $data) = @_;
    nstore($data, "/$temp_dir/sess_$sid");
}

sub cookie_exists {
    my ($name) = @_;
    return param($name);
}

